namespace sv_6acae8c28eb04252a93a9e9967571bfd.Models;

public class ApplicationModel
{
    // Step 1: Personal Info
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    // Track which steps have been completed
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_6acae8c28eb04252a93a9e9967571bfd.Models;

namespace sv_6acae8c28eb04252a93a9e9967571bfd.Services;

/// <summary>
/// Singleton store that bridges static SSR (layout) and interactive server (pages).
/// Keyed by a session cookie so each user has isolated state.
/// </summary>
public class ApplicationStateStore
{
    private readonly ConcurrentDictionary<string, ApplicationEntry> _store = new();

    public ApplicationModel GetOrCreate(string sessionId)
    {
        var entry = _store.GetOrAdd(sessionId, _ => new ApplicationEntry());
        entry.LastAccessed = DateTime.UtcNow;
        return entry.Model;
    }

    /// <summary>
    /// Remove entries older than the specified duration to prevent unbounded growth.
    /// </summary>
    public void Cleanup(TimeSpan maxAge)
    {
        var cutoff = DateTime.UtcNow - maxAge;
        foreach (var kvp in _store)
        {
            if (kvp.Value.LastAccessed < cutoff)
            {
                _store.TryRemove(kvp.Key, out _);
            }
        }
    }

    private class ApplicationEntry
    {
        public ApplicationModel Model { get; } = new();
        public DateTime LastAccessed { get; set; } = DateTime.UtcNow;
    }
}

namespace sv_6acae8c28eb04252a93a9e9967571bfd.Services;

/// <summary>
/// Periodically removes expired wizard sessions from the state store.
/// </summary>
public class StoreCleanupService(ApplicationStateStore store) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromMinutes(10), stoppingToken);
            store.Cleanup(TimeSpan.FromHours(2));
        }
    }
}

