@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject sv_6acae8c28eb04252a93a9e9967571bfd.Services.ApplicationStateStore Store
@inject IHttpContextAccessor HttpContextAccessor

@{
    // The layout renders statically (SSR), so HttpContext is available.
    // Read the session cookie to look up wizard state for the progress bar.
    var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
    var model = string.IsNullOrEmpty(sessionId) ? null : Store.GetOrCreate(sessionId);
    var completed = model?.CompletedSteps ?? new HashSet<int>();

    var currentPath = Nav.ToBaseRelativePath(Nav.Uri).TrimStart('/');
    var currentStep = currentPath switch
    {
        "apply/personal-info" => 1,
        "apply/experience" => 2,
        "apply/references" => 3,
        "apply/review" => 4,
        _ => 0
    };
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        @if (currentStep > 0)
        {
            <div class="wizard-header px-4 py-3">
                <h5 class="mb-2">Job Application — Step @currentStep of 4</h5>
                <div class="wizard-steps">
                    @for (int i = 1; i <= 4; i++)
                    {
                        var step = i;
                        var label = step switch
                        {
                            1 => "Personal Info",
                            2 => "Experience",
                            3 => "References",
                            4 => "Review",
                            _ => ""
                        };
                        var href = step switch
                        {
                            1 => "apply/personal-info",
                            2 => "apply/experience",
                            3 => "apply/references",
                            4 => "apply/review",
                            _ => ""
                        };
                        var isActive = step == currentStep;
                        var isCompleted = completed.Contains(step);

                        <a href="@href"
                           class="wizard-step @(isActive ? "active" : "") @(isCompleted ? "completed" : "")">
                            <span class="step-number">
                                @if (isCompleted && !isActive)
                                {
                                    <span>&#10003;</span>
                                }
                                else
                                {
                                    @step
                                }
                            </span>
                            <span class="step-label">@label</span>
                        </a>
                    }
                </div>
            </div>
        }

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

.wizard-header {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
}

.wizard-steps {
    display: flex;
    gap: 0.25rem;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 1rem;
    border-radius: 0.375rem;
    text-decoration: none;
    color: #6c757d;
    font-size: 0.9rem;
    transition: background-color 0.15s;
}

.wizard-step:hover {
    background-color: #e9ecef;
    text-decoration: none;
    color: #495057;
}

.wizard-step.active {
    background-color: #0d6efd;
    color: white;
    font-weight: 600;
}

.wizard-step.active:hover {
    background-color: #0b5ed7;
    color: white;
}

.wizard-step.completed {
    color: #198754;
}

.wizard-step.completed.active {
    color: white;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.6rem;
    height: 1.6rem;
    border-radius: 50%;
    border: 2px solid currentColor;
    font-size: 0.8rem;
    font-weight: 700;
    flex-shrink: 0;
}

.wizard-step.active .step-number {
    border-color: white;
}

.step-label {
    white-space: nowrap;
}

@media (max-width: 640.98px) {
    .step-label {
        display: none;
    }
}

/* Inherit the main layout structural styles */
.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

::deep .sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

    ::deep .sidebar {
        width: 250px;
        height: 100vh;
        position: sticky;
        top: 0;
    }

    .wizard-header, article {
        padding-left: 2rem !important;
        padding-right: 1.5rem !important;
    }
}

#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    box-sizing: border-box;
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

    #blazor-error-ui .dismiss {
        cursor: pointer;
        position: absolute;
        right: 0.75rem;
        top: 0.5rem;
    }

