@page "/apply/personal-info"
@layout WizardLayout
@rendermode InteractiveServer

@inject sv_6acae8c28eb04252a93a9e9967571bfd.Services.ApplicationStateStore Store
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Personal Info — Apply</PageTitle>

<h1>Personal Information</h1>

<EditForm Model="_form" OnValidSubmit="Next" FormName="personal-info">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_form.FullName" />
        <ValidationMessage For="() => _form.FullName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="_form.Email" />
        <ValidationMessage For="() => _form.Email" />
    </div>

    <div class="d-flex justify-content-end">
        <button type="submit" class="btn btn-primary">Next &rarr;</button>
    </div>
</EditForm>

@code {
    private FormModel _form = new();

    private string _sessionId = "";

    protected override void OnInitialized()
    {
        _sessionId = GetSessionId();
        var model = Store.GetOrCreate(_sessionId);
        _form.FullName = model.FullName;
        _form.Email = model.Email;
    }

    private void Next()
    {
        var model = Store.GetOrCreate(_sessionId);
        model.FullName = _form.FullName;
        model.Email = _form.Email;
        model.CompletedSteps.Add(1);

        Nav.NavigateTo("apply/experience", forceLoad: true);
    }

    private string GetSessionId()
    {
        return HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
    }

    private class FormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Name is required.")]
        public string FullName { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Email is required.")]
        [System.ComponentModel.DataAnnotations.EmailAddress(ErrorMessage = "Invalid email address.")]
        public string Email { get; set; } = "";
    }
}

@page "/apply/experience"
@layout WizardLayout
@rendermode InteractiveServer

@inject sv_6acae8c28eb04252a93a9e9967571bfd.Services.ApplicationStateStore Store
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

@using sv_6acae8c28eb04252a93a9e9967571bfd.Models

<PageTitle>Experience — Apply</PageTitle>

<h1>Work Experience</h1>

@if (_jobs.Count == 0)
{
    <p class="text-muted">No job history entries yet. Add one below.</p>
}
else
{
    <div class="mb-3">
        @foreach (var (job, idx) in _jobs.Select((j, i) => (j, i)))
        {
            <div class="card mb-2">
                <div class="card-body py-2 px-3 d-flex justify-content-between align-items-center">
                    <span><strong>@job.Title</strong> at @job.Company (@job.Years)</span>
                    <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(idx)">Remove</button>
                </div>
            </div>
        }
    </div>
}

<div class="card mb-4">
    <div class="card-body">
        <h6>Add Job</h6>
        <div class="row g-2">
            <div class="col-md-4">
                <input class="form-control" placeholder="Company" @bind="_newJob.Company" />
            </div>
            <div class="col-md-4">
                <input class="form-control" placeholder="Job Title" @bind="_newJob.Title" />
            </div>
            <div class="col-md-2">
                <input class="form-control" placeholder="Years" @bind="_newJob.Years" />
            </div>
            <div class="col-md-2 d-grid">
                <button type="button" class="btn btn-outline-primary" @onclick="AddJob">Add</button>
            </div>
        </div>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-outline-secondary" @onclick="Back">&larr; Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private List<JobEntry> _jobs = [];
    private JobEntry _newJob = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        _sessionId = GetSessionId();
        var model = Store.GetOrCreate(_sessionId);
        // Work on a copy of the list so we can cancel
        _jobs = model.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company,
            Title = j.Title,
            Years = j.Years
        }).ToList();
    }

    private void AddJob()
    {
        if (string.IsNullOrWhiteSpace(_newJob.Company) && string.IsNullOrWhiteSpace(_newJob.Title))
            return;

        _jobs.Add(_newJob);
        _newJob = new();
    }

    private void RemoveJob(int index) => _jobs.RemoveAt(index);

    private void SaveState()
    {
        var model = Store.GetOrCreate(_sessionId);
        model.JobHistory = _jobs.Select(j => new JobEntry
        {
            Company = j.Company,
            Title = j.Title,
            Years = j.Years
        }).ToList();
        model.CompletedSteps.Add(2);
    }

    private void Next()
    {
        SaveState();
        Nav.NavigateTo("apply/references", forceLoad: true);
    }

    private void Back()
    {
        SaveState();
        Nav.NavigateTo("apply/personal-info", forceLoad: true);
    }

    private string GetSessionId()
    {
        return HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
    }
}

@page "/apply/references"
@layout WizardLayout
@rendermode InteractiveServer

@inject sv_6acae8c28eb04252a93a9e9967571bfd.Services.ApplicationStateStore Store
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

@using sv_6acae8c28eb04252a93a9e9967571bfd.Models

<PageTitle>References — Apply</PageTitle>

<h1>References</h1>

@if (_refs.Count == 0)
{
    <p class="text-muted">No references added yet. Add one below.</p>
}
else
{
    <div class="mb-3">
        @foreach (var (r, idx) in _refs.Select((r, i) => (r, i)))
        {
            <div class="card mb-2">
                <div class="card-body py-2 px-3 d-flex justify-content-between align-items-center">
                    <span><strong>@r.Name</strong> — @r.Relationship, @r.Phone</span>
                    <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(idx)">Remove</button>
                </div>
            </div>
        }
    </div>
}

<div class="card mb-4">
    <div class="card-body">
        <h6>Add Reference</h6>
        <div class="row g-2">
            <div class="col-md-4">
                <input class="form-control" placeholder="Name" @bind="_newRef.Name" />
            </div>
            <div class="col-md-4">
                <input class="form-control" placeholder="Relationship" @bind="_newRef.Relationship" />
            </div>
            <div class="col-md-4">
                <input class="form-control" placeholder="Phone" @bind="_newRef.Phone" />
            </div>
        </div>
        <button type="button" class="btn btn-outline-primary mt-2" @onclick="AddRef">Add</button>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-outline-secondary" @onclick="Back">&larr; Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private List<ReferenceContact> _refs = [];
    private ReferenceContact _newRef = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        _sessionId = GetSessionId();
        var model = Store.GetOrCreate(_sessionId);
        _refs = model.References.Select(r => new ReferenceContact
        {
            Name = r.Name,
            Relationship = r.Relationship,
            Phone = r.Phone
        }).ToList();
    }

    private void AddRef()
    {
        if (string.IsNullOrWhiteSpace(_newRef.Name))
            return;

        _refs.Add(_newRef);
        _newRef = new();
    }

    private void RemoveRef(int index) => _refs.RemoveAt(index);

    private void SaveState()
    {
        var model = Store.GetOrCreate(_sessionId);
        model.References = _refs.Select(r => new ReferenceContact
