@layout WizardLayout
@rendermode InteractiveServer

@inject sv_6acae8c28eb04252a93a9e9967571bfd.Services.ApplicationStateStore Store
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

@using sv_6acae8c28eb04252a93a9e9967571bfd.Models

<PageTitle>Review — Apply</PageTitle>

<h1>Review Your Application</h1>
<p class="text-muted">Please review all information before submitting.</p>

<div class="card mb-3">
    <div class="card-header"><strong>Step 1 — Personal Information</strong></div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt>
            <dd class="col-sm-9">@_model.FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@_model.Email</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>Step 2 — Work Experience</strong></div>
    <div class="card-body">
        @if (_model.JobHistory.Count == 0)
        {
            <p class="text-muted mb-0">No job history provided.</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var job in _model.JobHistory)
                {
                    <li class="list-group-item px-0">
                        <strong>@job.Title</strong> at @job.Company — @job.Years
                    </li>
                }
            </ul>
        }
    </div>
</div>

<div class="card mb-4">
    <div class="card-header"><strong>Step 3 — References</strong></div>
    <div class="card-body">
        @if (_model.References.Count == 0)
        {
            <p class="text-muted mb-0">No references provided.</p>
        }
        else
        {
            <ul class="list-group list-group-flush">
                @foreach (var r in _model.References)
                {
                    <li class="list-group-item px-0">
                        <strong>@r.Name</strong> — @r.Relationship, @r.Phone
                    </li>
                }
            </ul>
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-outline-secondary" @onclick="Back">&larr; Back</button>
    <button type="button" class="btn btn-success" @onclick="Submit" disabled="@_submitted">
        @if (_submitted)
        {
            <span>✓ Submitted</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">
        Your application has been submitted successfully!
    </div>
}

@code {
    private ApplicationModel _model = new();
    private bool _submitted;
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        _sessionId = GetSessionId();
        _model = Store.GetOrCreate(_sessionId);
        _model.CompletedSteps.Add(4);
    }

    private void Submit()
    {
        _submitted = true;
