    }

    private void Back()
    {
        Nav.NavigateTo("apply/references", forceLoad: true);
    }

    private string GetSessionId()
    {
        return HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
    }
}
