@page "/apply/experience"
@layout WizardLayout
@rendermode InteractiveServer

@inject sv_6acae8c28eb04252a93a9e9967571bfd.Services.ApplicationStateStore Store
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor

@using sv_6acae8c28eb04252a93a9e9967571bfd.Models

<PageTitle>Experience — Apply</PageTitle>

<h1>Work Experience</h1>

@if (_jobs.Count == 0)
{
    <p class="text-muted">No job history entries yet. Add one below.</p>
}
else
{
    <div class="mb-3">
        @foreach (var (job, idx) in _jobs.Select((j, i) => (j, i)))
        {
            <div class="card mb-2">
                <div class="card-body py-2 px-3 d-flex justify-content-between align-items-center">
                    <span><strong>@job.Title</strong> at @job.Company (@job.Years)</span>
                    <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(idx)">Remove</button>
                </div>
            </div>
        }
    </div>
}

<div class="card mb-4">
    <div class="card-body">
        <h6>Add Job</h6>
        <div class="row g-2">
            <div class="col-md-4">
                <input class="form-control" placeholder="Company" @bind="_newJob.Company" />
            </div>
            <div class="col-md-4">
                <input class="form-control" placeholder="Job Title" @bind="_newJob.Title" />
            </div>
            <div class="col-md-2">
                <input class="form-control" placeholder="Years" @bind="_newJob.Years" />
            </div>
            <div class="col-md-2 d-grid">
                <button type="button" class="btn btn-outline-primary" @onclick="AddJob">Add</button>
            </div>
        </div>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-outline-secondary" @onclick="Back">&larr; Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private List<JobEntry> _jobs = [];
    private JobEntry _newJob = new();
    private string _sessionId = "";

    protected override void OnInitialized()
    {
        _sessionId = GetSessionId();
        var model = Store.GetOrCreate(_sessionId);
        // Work on a copy of the list so we can cancel
        _jobs = model.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company,
            Title = j.Title,
            Years = j.Years
        }).ToList();
    }

    private void AddJob()
    {
        if (string.IsNullOrWhiteSpace(_newJob.Company) && string.IsNullOrWhiteSpace(_newJob.Title))
            return;

        _jobs.Add(_newJob);
        _newJob = new();
    }

    private void RemoveJob(int index) => _jobs.RemoveAt(index);

    private void SaveState()
    {
        var model = Store.GetOrCreate(_sessionId);
        model.JobHistory = _jobs.Select(j => new JobEntry
        {
            Company = j.Company,
            Title = j.Title,
            Years = j.Years
        }).ToList();
        model.CompletedSteps.Add(2);
    }

    private void Next()
    {
        SaveState();
        Nav.NavigateTo("apply/references", forceLoad: true);
    }

    private void Back()
    {
        SaveState();
        Nav.NavigateTo("apply/personal-info", forceLoad: true);
    }

    private string GetSessionId()
    {
        return HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
    }
}

